const output = $input.first().json.output || "";

let parsed;

try {
  parsed = JSON.parse(output);
} catch (e) {
  const match = output.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (e2) {
      parsed = {};
    }
  } else {
    parsed = {};
  }
}

const ctx = $("Montar Contexto").item.json || {};
const inputOriginal = $("Normalizar Dados Pedido").item.json || {};

function numero(valor) {
  if (typeof valor === "number") return valor;

  const limpo = String(valor || "")
    .replace(/[^\d,.-]/g, "")
    .replace(",", ".");

  return Number(limpo) || 0;
}

const produtosSolicitados =
  parsed.produtos_solicitados ||
  parsed.itens_pedido ||
  parsed.itens ||
  [];

const itensPedido = Array.isArray(produtosSolicitados)
  ? produtosSolicitados.map((item) => ({
      produto_id: item.produto_id || item.id || "",
      nome: item.nome || item.produto || item.Produto || "",
      quantidade: numero(item.quantidade || item.Quantidade || 0),
      unidade: item.unidade || item.Unidade || "",
      preco_unitario: numero(item.preco_unitario || item.preco || item.Preco || 0),
      estoque: numero(item.estoque || item.Estoque || 0),
    })).filter((item) => item.nome)
  : [];

const resumoItens = itensPedido.length
  ? itensPedido.map((item) =>
      `- ${item.quantidade} ${item.unidade || ""} de ${item.nome}`
    ).join("\n")
  : "";

const endereco =
  parsed.endereco_entrega ||
  parsed.endereco ||
  parsed.Endereco ||
  "";

const formaPagamento =
  parsed.forma_pagamento ||
  parsed.pagamento ||
  parsed.FormaPagamento ||
  "";

const observacoes =
  parsed.observacoes ||
  parsed.Observacoes ||
  "";

const pedidoCompleto = Boolean(
  parsed.pedido_completo === true ||
  parsed.pedido_completo === "true" ||
  (
    itensPedido.length > 0 &&
    endereco &&
    formaPagamento
  )
);

const resposta =
  parsed.resposta ||
  (
    pedidoCompleto
      ? `Pedido confirmado com os seguintes itens:\n${resumoItens}`
      : `Perfeito, ${inputOriginal.nome_cliente || parsed.cliente || "cliente"}! Anotei:\n${resumoItens || "os itens do seu pedido"}\n\nPara finalizar seu pedido, me informe por favor:\n1. Endereço de entrega\n2. Forma de pagamento: Pix, dinheiro ou cartão`
  );

return [{
  json: {
    resposta,
    pedido_completo: pedidoCompleto,
    dados_coletados: JSON.stringify({
      cliente: parsed.cliente || parsed.Cliente || inputOriginal.nome_cliente || "",
      itens_pedido: itensPedido,
      endereco_entrega: endereco,
      forma_pagamento: formaPagamento,
      observacoes,
      mensagem: parsed.mensagem || parsed.Mensagem || inputOriginal.mensagem || ""
    }),
    cliente: parsed.cliente || parsed.Cliente || inputOriginal.nome_cliente || "",
    itens_pedido: itensPedido,
    produto: itensPedido[0]?.nome || "",
    quantidade: itensPedido[0]?.quantidade || 0,
    unidade: itensPedido[0]?.unidade || "",
    preco: itensPedido[0]?.preco_unitario || 0,
    estoque: itensPedido[0]?.estoque || 0,
    endereco_entrega: endereco,
    forma_pagamento: formaPagamento,
    observacoes,
    mensagem: parsed.mensagem || parsed.Mensagem || inputOriginal.mensagem || "",
    telefone: inputOriginal.telefone || ctx.telefone || "",
    nome_cliente: inputOriginal.nome_cliente || ctx.nome_cliente || parsed.cliente || "",
    canal: inputOriginal.canal || ctx.canal || "whatsapp"
  }
}];

