const msgOriginal = $json.mensagem ?? '';
const telefone = $json.telefone;
const nome_cliente = $json.nome_cliente;

let msg = msgOriginal
  .replace(/\d+\s*(kg|g|gramas?|litros?|ml|un|unidades?|quilos?)/gi, '')
  .replace(/r\$\s*\d+[.,]?\d*/gi, '')
  .replace(/\d+/g, '')
  .trim();

msg = msg.replace(/\b(eu|quero|comprar|pra|para|me|preciso|gostaria|queria|favor|por favor|obrigado|olá|ola|oi|bom dia|boa tarde|boa noite)\b/gi, '');
msg = msg.replace(/\s+/g, ' ').trim();

const partes = msg.split(/\s*,\s*|\s+e\s+/);
const produtos = partes.map(p => p.trim()).filter(p => p.length > 2);

return [{
  json: {
    produtos_busca: produtos.length ? produtos : [msg],
    mensagem: msgOriginal,
    telefone,
    nome_cliente
  }
}];

const inputOriginal = $('Normalizar Dados Pedido').first().json;
const mensagem     = inputOriginal.mensagem    || '';
const nome_cliente = inputOriginal.nome_cliente|| '';
const telefone     = inputOriginal.telefone    || '';

// ─── historico de mensagens anteriores ───────────────────────────────────────
let historicoTexto = '';
try {
  const todasMensagens = $('Get many rows').all();

  if (todasMensagens && todasMensagens.length > 0) {
    const campos = ['content','mensagem','message','text'];

    const mensagensValidas = todasMensagens
      .filter(item => campos.some(c => (item.json || {})[c]))
      .sort((a, b) =>
        new Date(a.json.created_at || 0).getTime() -
        new Date(b.json.created_at || 0).getTime()
      )
      .slice(-15);

    if (mensagensValidas.length > 0) {
      const linhas = mensagensValidas.map(item => {
        const j    = item.json;
        const role = (j.role === 'user' || j.role === 'cliente' || j.type === 'human')
                     ? 'Cliente' : 'Assistente';
        const txt  = j.content || j.mensagem || j.message || j.text || '';
        return role + ': ' + txt;
      });
      historicoTexto = '\n\nHistórico de conversa:\n' + linhas.join('\n');
    }
  }
} catch (e) {
  historicoTexto = '';
}

// ─── detecta quantidade / unidade na mensagem atual ──────────────────────────
const qtMatch = mensagem.match(
  /(\d+(?:[.,]\d+)?)\s*(kg|kgs|quilos?|g|gramas?|litros?|l\b|ml|un|unidades?|cx|caixas?|sacos?|pct|pacotes?)/i
);
const quantidade    = qtMatch ? qtMatch[1] : null;
const unidadePedido = qtMatch ? qtMatch[2] : null;
const qtdTexto      = quantidade
  ? '\n\nQuantidade detectada: ' + quantidade + ' ' + unidadePedido
  : '';

return [{
  json: {
    contexto: 'Cliente: ' + nome_cliente +
              '\nTelefone: ' + telefone +
              '\n\nMensagem atual: ' + mensagem +
              qtdTexto +
              historicoTexto,
    tem_endereco: false,
    mensagem,
    nome_cliente,
    telefone
  }
}];
